solution.javascript:
import { test, expect } from '@playwright/test';

test('handle dropdowns', async ({ page }) => {
  await page.goto('https://practice.expandtesting.com/dropdown');

  await page.selectOption('#dropdown', '1');
  let selectedValue = await page.locator('#dropdown').inputValue();
  expect(selectedValue).toBe('1');

  await page.selectOption('#dropdown', { label: 'Option 2' });
  selectedValue = await page.locator('#dropdown').inputValue();
  expect(selectedValue).toBe('2');

  await page.selectOption('#country', { label: 'United States' });
  const countryValue = await page.locator('#country').inputValue();
  expect(countryValue).toBe('US');
});

